+  const writeKeychain = options?.writeKeychain ?? writeClaudeCliKeychainCredentials;
+  const writeFile =
+    options?.writeFile ??
+    ((credentials, fileOptions) => writeClaudeCliFileCredentials(credentials, fileOptions));
